void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var star = geo::PointSet<db>();
	fa(i, 1, n) {
		int x, y; cin >> x >> y;
		star.pb({ x,y });
	}
	var cloud = vector<geo::Line<db>>();
	fa(i, 1, m) {
		int u1, v1, u2, v2; cin >> u1 >> v1 >> u2 >> v2;
		cloud.pb({ {u1,v1},{u2,v2} });
	}

	var last_shadow = vector<pair<db, db>>();
	for (const var& p : star) {
		var shadow = vector<pair<db, db>>();

		for (const var& [p1, p2] : cloud) {
			var now = geo::Segment<db>(p1, p2);
			if (geo::point_segment_relation(p, now) == 1) {
				shadow.clear();
				shadow.pb({ -1e32,1e32 });
				break;
			}


			if ((geo::cmp(p2.y, p.y) == 0 or geo::cmp(p2.y, p.y) == 1) and
				(geo::cmp(p1.y, p.y) == 0 or geo::cmp(p1.y, p.y) == 1))
				continue;


			if ((geo::cmp(p2.y, p.y) == 0 or geo::cmp(p2.y, p.y) == 1) and
				(geo::cmp(p1.y, p.y) == -1) or
				(geo::cmp(p1.y, p.y) == 0 or geo::cmp(p1.y, p.y) == 1) and
				(geo::cmp(p2.y, p.y) == -1)) {
				db l = -1e32, r = 1e32;
				var A = p1 - p, B = p2 - p; // A B 向量
				int res = geo::vector_vector_relation(A, B);
				if ((geo::cmp(p2.y, p.y) == 0 or geo::cmp(p2.y, p.y) == 1) and
					(geo::cmp(p1.y, p.y) == -1)) {
					db tmp = p.x - p.y * (p.x - p1.x) / (p.y - p1.y);
					if (res == 2)shadow.pb({ l, tmp });
					else shadow.pb({ tmp, r });
				}
				else {
					db tmp = p.x - p.y * (p.x - p2.x) / (p.y - p2.y);
					if (res == 1)shadow.pb({ l, tmp });
					else shadow.pb({ tmp, r });
				}
			}
			else {
				db l = p.x - p.y * (p.x - p1.x) / (p.y - p1.y);
				db r = p.x - p.y * (p.x - p2.x) / (p.y - p2.y);

				if (l > r)swap(l, r);
				shadow.pb({ l, r });
			}
		}
		sort(all(shadow));

		if (shadow.empty()) {
			cout << 0 << endl;
			return;
		}

		// 求并集
		var nshadow = vector<pair<db, db>>();
		var[l, r] = shadow[0];
		fa(i, 1, vs(shadow)) {
			var[nl, nr] = shadow[i];
			if (geo::cmp(nl, r) == 1) {
				nshadow.pb({ l,r });
				l = nl, r = nr;
			}
			else r = max(r, nr);
		}
		nshadow.pb({ l,r });
		shadow = move(nshadow);

		// 求交集
		if (last_shadow.empty())last_shadow = move(shadow);
		else {
			var nlast_shadow = vector<pair<db, db>>();
			for (const var& [l, r] : last_shadow) {
				for (const var& [nl, nr] : shadow) {
					db L = max(l, nl), R = min(r, nr);
					if (L > R)continue;
					nlast_shadow.pb({ L, R });
				}
			}
			last_shadow = move(nlast_shadow);

			if (last_shadow.empty()) {
				cout << 0 << endl;
				return;
			}
		}
	}

	db ans = 0;
	for (const var& [l, r] : last_shadow)ans += r - l;
	if (ans > 1e9)cout << -1 << endl;
	else cout << fixed << setprecision(12) << ans << endl;
	return;
}
